import { useState } from 'react';
import {
  Shield, Server, Gamepad2, Library, Database, Leaf,
  ArrowUpRight, X, CheckCircle2, Circle
} from 'lucide-react';
import SectionHeader from './SectionHeader';
import { useApp } from '../context/AppContext';
import t from '../i18n/translations';

/* ─── Project metadata (icons + colors) ─── */
const meta = [
  {
    Icon: Shield,
    gradient: 'from-teal/40 via-teal/10 to-transparent',
    glow: 'rgba(42,157,143,0.35)',
    accent: '#2a9d8f',
    tagColor: 'bg-teal/15 text-teal2 border-teal/20',
  },
  {
    Icon: Library,
    gradient: 'from-blue-400/35 via-blue-400/10 to-transparent',
    glow: 'rgba(77,143,255,0.3)',
    accent: '#4d8fff',
    tagColor: 'bg-blue-400/10 text-blue-500 border-blue-400/20',
  },
  {
    Icon: Gamepad2,
    gradient: 'from-amber/40 via-amber/10 to-transparent',
    glow: 'rgba(240,165,0,0.3)',
    accent: '#f0a500',
    tagColor: 'bg-amber/15 text-amber2 border-amber/20',
  },
  {
    Icon: Gamepad2,
    gradient: 'from-amber/35 via-amber/8 to-transparent',
    glow: 'rgba(240,165,0,0.25)',
    accent: '#f0a500',
    tagColor: 'bg-amber/15 text-amber2 border-amber/20',
  },
  {
    Icon: Database,
    gradient: 'from-purple-400/35 via-purple-400/10 to-transparent',
    glow: 'rgba(168,85,247,0.3)',
    accent: '#a855f7',
    tagColor: 'bg-purple-400/10 text-purple-500 border-purple-400/20',
  },
  {
    Icon: Leaf,
    gradient: 'from-coral/35 via-coral/10 to-transparent',
    glow: 'rgba(231,111,81,0.3)',
    accent: '#e76f51',
    tagColor: 'bg-coral/10 text-coral border-coral/20',
  },
];

const chipsEn = [
  ['React', 'Node.js', 'SQL Server', 'JWT', 'Express'],
  ['HTML', 'CSS', 'JavaScript'],
  ['Game Engine', 'Graphics', 'Docs'],
  ['Textures', 'Lighting', 'UX'],
  ['MS Access', 'Relational DB', 'Team ×4'],
  ['ESG', 'Strategy', 'Forage'],
];
const chipsAr = [
  ['React', 'Node.js', 'SQL Server', 'JWT', 'Express'],
  ['HTML', 'CSS', 'JavaScript'],
  ['محرك اللعبة', 'رسومات', 'توثيق'],
  ['تكسچر', 'إضاءة', 'تجربة مستخدم'],
  ['MS Access', 'قاعدة بيانات', 'فريق ×4'],
  ['الاستدامة', 'استراتيجية', 'Forage'],
];

/* ─── Examor detail modal ─── */
const examorFeatures = {
  en: [
    { done: true,  text: 'Role-based system: Admin / Doctor / Student' },
    { done: true,  text: 'MCQ, True/False, Essay question types' },
    { done: true,  text: 'Auto-grading for MCQ & True/False' },
    { done: true,  text: 'Unique exam code per exam' },
    { done: true,  text: 'JWT auth + bcrypt password hashing' },
    { done: true,  text: 'SQL Injection protection' },
    { done: true,  text: '20+ REST API endpoints' },
    { done: true,  text: 'Countdown timer with auto-submit' },
    { done: false, text: 'Frontend dashboards (in progress)' },
    { done: false, text: 'Deploy on Vercel / Render' },
  ],
  ar: [
    { done: true,  text: 'نظام أدوار: Admin / Doctor / Student' },
    { done: true,  text: 'MCQ + صح/خطأ + مقالي' },
