/* ─── Liquid Glass card ─── */
function GlassCard({ p, m, chips, index, isExamor, inProgress, dark, lang, onExamorClick }) {
  const [hovered, setHovered] = useState(false);
  const [mouse, setMouse]     = useState({ x: 50, y: 50 });

  const handleMouseMove = e => {
    const r = e.currentTarget.getBoundingClientRect();
    setMouse({
      x: ((e.clientX - r.left) / r.width  * 100).toFixed(1),
      y: ((e.clientY - r.top)  / r.height * 100).toFixed(1),
    });
  };

  /* Glass surfaces */
  const glassBg = dark
    ? 'rgba(255,255,255,0.04)'
    : 'rgba(255,255,255,0.55)';
  const glassBorder = dark
    ? 'rgba(255,255,255,0.10)'
    : 'rgba(255,255,255,0.75)';
  const glassInner = dark
    ? 'rgba(255,255,255,0.02)'
    : 'rgba(255,255,255,0.35)';
  const tBase  = dark ? '#f0f0f8' : '#1a1a2e';
  const tMuted = dark ? 'rgba(255,255,255,0.5)' : '#5a5a72';
  const chipBg = dark ? 'rgba(255,255,255,0.06)' : 'rgba(255,255,255,0.6)';

  return (
    <div
      className={`reveal ${index === 1 ? 'delay-1' : index === 2 ? 'delay-2' : index === 3 ? 'delay-3' : ''} relative rounded-2xl overflow-hidden transition-all duration-300 flex flex-col cursor-default`}
      style={{
        background: glassBg,
        border: `1px solid ${glassBorder}`,
        backdropFilter: 'blur(20px) saturate(160%)',
        WebkitBackdropFilter: 'blur(20px) saturate(160%)',
        boxShadow: hovered
          ? `0 20px 60px ${m.glow}, 0 0 0 1px ${glassBorder}, inset 0 1px 0 ${glassInner}`
          : `0 4px 24px rgba(0,0,0,0.08), 0 0 0 1px ${glassBorder}, inset 0 1px 0 ${glassInner}`,
        transform: hovered ? 'translateY(-6px) scale(1.005)' : 'translateY(0) scale(1)',
      }}
      onMouseEnter={() => setHovered(true)}
      onMouseLeave={() => setHovered(false)}
      onMouseMove={handleMouseMove}
      onClick={isExamor ? onExamorClick : undefined}
      style2={{cursor: isExamor ? 'pointer' : 'default'}}
    >
      {/* Gradient glow blob — follows mouse */}
      <div
        className="absolute inset-0 pointer-events-none transition-opacity duration-300 rounded-2xl"
        style={{
          opacity: hovered ? 1 : 0,
          background: `radial-gradient(circle at ${mouse.x}% ${mouse.y}%, ${m.glow}, transparent 60%)`,
        }}
      />

      {/* Top specular highlight */}
      <div
        className="absolute top-0 left-4 right-4 h-[1px] pointer-events-none"
        style={{ background: `linear-gradient(90deg, transparent, ${glassBorder}, transparent)` }}
      />

      {/* Content */}
      <div className="relative z-10 p-8 flex flex-col h-full">
        {/* Header */}
        <div className="flex items-start justify-between mb-5">
          <div className="flex items-center gap-3">
            {/* Icon pill */}
            <div
              className="w-10 h-10 rounded-xl flex items-center justify-center"
              style={{
                background: `linear-gradient(135deg, ${m.accent}22, ${m.accent}11)`,
                border: `1px solid ${m.accent}33`,
                color: m.accent,
              }}>
              <m.Icon size={18} />
            </div>
            <span
              className={`text-[.65rem] font-semibold tracking-wider uppercase px-2.5 py-1 rounded-full border ${m.tagColor}`}>
              {p.tag}
            </span>
          </div>
          {inProgress && (
            <span className="text-[.58rem] font-semibold bg-teal/10 text-teal2 border border-teal/20 px-2 py-0.5 rounded-full">
              🔄 In Progress
            </span>
          )}
        </div>

        {/* Title */}
        <h3 className="font-serif-display text-xl tracking-tight leading-snug mb-2" style={{ color: tBase }}>
          {p.title}
        </h3>

        {/* Description */}
        <p className="text-[.87rem] leading-[1.75] flex-1" style={{ color: tMuted }}>
          {p.desc}
        </p>

        {/* Examor stack */}
        {isExamor && (
          <div className="flex gap-1.5 flex-wrap mt-3">
            {['React', 'Node.js', 'SQL Server', 'JWT', 'Express'].map(tech => (
              <span key={tech}
                className="text-[.62rem] font-mono px-2 py-0.5 rounded-full border"
                style={{ background: `${m.accent}11`, borderColor: `${m.accent}30`, color: m.accent }}>
                {tech}
              </span>
            ))}
          </div>
        )}

        {/* Footer */}
        <div
          className="flex items-center justify-between mt-5 pt-4"
          style={{ borderTop: `1px solid ${glassBorder}` }}>
          <div className="flex gap-1.5 flex-wrap">
            {chips.map(c => (
              <span key={c}
                className="text-[.67rem] font-medium px-2 py-0.5 rounded border"
                style={{ background: chipBg, borderColor: glassBorder, color: tMuted }}>
                {c}
              </span>
            ))}
          </div>
          <div
            className="w-7 h-7 rounded-lg flex items-center justify-center transition-all duration-200"
            style={{
              background: hovered ? `${m.accent}22` : chipBg,
              border: `1px solid ${hovered ? m.accent + '44' : glassBorder}`,
              color: hovered ? m.accent : tMuted,
            }}>
            <ArrowUpRight size={13} />
          </div>
        </div>
      </div>
    </div>
  );
}

